  return (
    <header className={`${classes.header} ${scrolled ? classes.scrolled : ''}`}>
      <Container size="xl" className={classes.inner}>
        {/* 로고 */}
        <Link href="/" style={{ textDecoration: 'none' }}>
          <Group gap={8} className={classes.logo}>
            <NextImage
              src="/images/dg-logo-v2.png"
