                    )}
                    <Text size="sm" fw={500} c="var(--dg-text-dark)" className={classes.userName}>
                      {authDisplayName}
                    </Text>
                    <IconChevronDown size={14} color="var(--dg-text-muted)" />
                  </Group>
                </UnstyledButton>
              </Menu.Target>
              <Menu.Dropdown>
                {/* Tier card — 실제 로그인 시에만 */}
                {!demoRole && !rewardsLoading && (
                  <>
                    <div className={classes.tierCard}>
                      <Group gap={8} mb={6}>
                        <span style={{ fontSize: '1.1rem' }}>{currentTier.emoji}</span>
                        <div style={{ flex: 1 }}>
                          <Text size="xs" fw={700} c="var(--bm-text-dark)" lh={1.2}>
                            {currentTier.label}
                          </Text>
                          <Text size="xs" c="var(--bm-text-muted)" lh={1.2}>
                            {unlockedCount}/{totalCount} badges
                          </Text>
                        </div>
                      </Group>
                      <Progress
                        value={nextTier ? ((unlockedCount - currentTier.minBadges) / (nextTier.minBadges - currentTier.minBadges)) * 100 : 100}
                        color={currentTier.color}
                        size={4}
                        radius="xl"
                      />
                      {nextTier && (
                        <Text size="xs" c="var(--bm-text-muted)" mt={4}>
                          {nextTier.minBadges - unlockedCount} badge{nextTier.minBadges - unlockedCount !== 1 ? 's' : ''} to {nextTier.label}
                        </Text>
                      )}
                    </div>
                    <Menu.Divider />
                  </>
                )}
                <Menu.Label>{authDisplayEmail}{demoRole ? ` (${demoRole} demo)` : ''}</Menu.Label>

                {/* 역할별 메뉴 항목 */}
                {(!demoRole || demoRole === 'donor') && (
                  <Menu.Item
                    leftSection={<IconLayoutDashboard size={16} />}
                    component={Link}
                    href="/dashboard"
                  >
                    My Dashboard
                  </Menu.Item>
                )}
                {(!demoRole || demoRole === 'charity') && (
                  <Menu.Item
                    leftSection={<IconBuilding size={16} />}
                    component={Link}
                    href="/charity/dashboard"
                  >
                    Organisation Dashboard
                  </Menu.Item>
                )}
                {(!demoRole || demoRole === 'admin') && (
                  <Menu.Item
                    leftSection={<IconShieldCheck size={16} />}
                    component={Link}
                    href="/admin"
                  >
                    Admin Panel
                  </Menu.Item>
                )}
                {(!demoRole || demoRole === 'donor') && (
                  <Menu.Item
                    leftSection={<IconGift size={16} />}
                    component={Link}
                    href="/dashboard?tab=rewards"
                  >
                    My Rewards
                  </Menu.Item>
                )}
                <Menu.Item
                  leftSection={<IconSettings size={16} />}
                  component={Link}
                  href="/settings"
                >
                  Settings
                </Menu.Item>
                <Menu.Divider />
                <Menu.Item
                  leftSection={<IconLogout size={16} />}
                  color="red"
                  onClick={handleLogout}
                >
                  Log out
                </Menu.Item>
              </Menu.Dropdown>
            </Menu>
            </Group>
          ) : (
            // 비로그인 상태
            <>
              <Button
                component={Link}
                href="/auth"
                variant="subtle"
                color="dark"
                size="sm"
              >
                Log in
              </Button>
              <Button component={Link} href="/projects" color="terracotta" size="sm" radius="xl">
                Give Today
              </Button>
            </>
          )}
        </Group>

        {/* 모바일 햄버거 */}
        <Burger opened={opened} onClick={toggle} hiddenFrom="sm" size="sm" />
      </Container>

      {/* 모바일 드로어 */}
      <Drawer
        opened={opened}
        onClose={close}
        size="70%"
        padding="md"
        title="DearGiver"
        hiddenFrom="sm"
      >
        <Stack gap="md">
          {navLinks.map((link) => (
            <Link key={link.label} href={link.href} className={classes.mobileLink} onClick={close}>
              {link.label}
            </Link>
          ))}

          {user ? (
            <>
              <Group gap={8} py={8}>
                <Avatar
                  src={user.photoURL}
                  alt={user.displayName || 'User'}
                  size={28}
                  radius="xl"
                  color="sage"
                >
                  {getInitials(user.displayName)}
                </Avatar>
                <Text size="sm" fw={500}>{user.displayName || 'User'}</Text>
              </Group>
              <Button
                variant="outline"
                color="red"
                fullWidth
                leftSection={<IconLogout size={16} />}
                onClick={() => { handleLogout(); close(); }}
              >
                Log out
              </Button>
            </>
          ) : (
            <>
              <Button
                component={Link}
                href="/auth"
                variant="outline"
                color="dark"
                fullWidth
                onClick={close}
              >
                Log in
              </Button>
              <Button component={Link} href="/projects" color="terracotta" fullWidth radius="xl" onClick={close}>
                Give Today
              </Button>
            </>
          )}
        </Stack>
      </Drawer>
    </header>
  );
}

'use client';

import { useEffect, useRef, useState } from 'react';
import { Container, Title, Text, Box, Group, SimpleGrid } from '@mantine/core';
import { IconUsers, IconHeart, IconTree, IconBuildingBank } from '@tabler/icons-react';
import classes from './ImpactCounter.module.css';

interface CounterItem {
  icon: typeof IconUsers;
  value: number;
  prefix: string;
  suffix: string;
  label: string;
  color: string;
}

const counters: CounterItem[] = [
  { icon: IconHeart, value: 2847, prefix: '', suffix: '', label: 'Donations Made', color: 'var(--bm-terracotta)' },
  { icon: IconUsers, value: 1250, prefix: '', suffix: '+', label: 'Active Donors', color: 'var(--bm-sage-dark)' },
  { icon: IconBuildingBank, value: 174850, prefix: '$', suffix: '', label: 'Total Raised (NZD)', color: 'var(--bm-terracotta)' },
  { icon: IconTree, value: 48, prefix: '', suffix: '', label: 'Verified Charities', color: 'var(--bm-sage-dark)' },
];

function AnimatedCounter({ target, prefix, suffix, isVisible }: { target: number; prefix: string; suffix: string; isVisible: boolean }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    if (!isVisible) return;

    let start = 0;
    const duration = 2000;
    const startTime = performance.now();

    const easeOutExpo = (t: number): number => {
      return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
    };

    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const easedProgress = easeOutExpo(progress);
      const current = Math.round(easedProgress * target);

      setCount(current);

      if (progress < 1) {
        requestAnimationFrame(animate);
      }
    };

    requestAnimationFrame(animate);
  }, [isVisible, target]);

  // Format number with commas
  const formatted = count.toLocaleString('en-NZ');

  return (
    <span>
      {prefix}{formatted}{suffix}
    </span>
  );
}

export function ImpactCounter() {
  const sectionRef = useRef<HTMLElement>(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setIsVisible(true);
            // Also trigger reveal classes
            entry.target.querySelectorAll('.reveal, .revealScale').forEach((child) => {
              child.classList.add('visible');
            });
          }
        });
      },
      { threshold: 0.2 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }
    return () => observer.disconnect();
  }, []);

  return (
    <section className={classes.section} ref={sectionRef}>
      {/* Background decorations */}
      <div className={classes.bgBlob1} />
      <div className={classes.bgBlob2} />

      <Container size="lg" style={{ position: 'relative', zIndex: 1 }}>
        <Box ta="center" mb={48} className="reveal">
          <Text size="sm" fw={600} c="rgba(255,255,255,0.6)" tt="uppercase" mb={8} style={{ letterSpacing: '2px' }}>
            Our Impact
          </Text>
          <Title order={2} className={classes.heading}>
            Together, We&apos;re Making a Difference
          </Title>
          <Text size="md" c="rgba(255,255,255,0.6)" maw={480} mx="auto" mt={8}>
            Real numbers, real change. See how your generosity transforms communities across Aotearoa.
          </Text>
        </Box>

        <SimpleGrid cols={{ base: 2, sm: 4 }} spacing={24}>
          {counters.map((item, i) => (
            <div
              key={item.label}
              className={`${classes.counterCard} revealScale revealDelay${i + 1}`}
            >
              <div className={classes.iconWrapper} style={{ background: `${item.color}20` }}>
                <item.icon size={28} color={item.color} stroke={1.5} />
              </div>
              <Text className={classes.counterValue}>
                <AnimatedCounter target={item.value} prefix={item.prefix} suffix={item.suffix} isVisible={isVisible} />
              </Text>
              <Text size="sm" c="rgba(255,255,255,0.6)" fw={500}>
                {item.label}
              </Text>
            </div>
          ))}
        </SimpleGrid>
      </Container>
    </section>
  );
}

