'use client';

import {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  type ReactNode,
} from 'react';

// --- 타입 ---
export type FavoriteType = 'project' | 'organization';

interface FavoritesState {
  projects: string[];
  organizations: string[];
}

interface FavoritesContextType {
  favorites: FavoritesState;
  toggleFavorite: (type: FavoriteType, id: string) => void;
  isFavorite: (type: FavoriteType, id: string) => boolean;
  getFavoriteCount: () => number;
  getFavoritesByType: (type: FavoriteType) => string[];
  clearAll: () => void;
}

const STORAGE_KEY = 'bm-favorites';

const defaultState: FavoritesState = {
  projects: [],
  organizations: [],
};

// --- Context ---
const FavoritesContext = createContext<FavoritesContextType | undefined>(undefined);

// --- localStorage 헬퍼 ---
// NOTE: 나중에 Firestore로 마이그레이션할 때 이 두 함수만 교체하면 됩니다
function loadFromStorage(): FavoritesState {
  if (typeof window === 'undefined') return defaultState;
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return defaultState;
    const parsed = JSON.parse(raw);
    return {
      projects: Array.isArray(parsed.projects) ? parsed.projects : [],
      organizations: Array.isArray(parsed.organizations) ? parsed.organizations : [],
    };
  } catch {
    return defaultState;
  }
}

function saveToStorage(state: FavoritesState): void {
  if (typeof window === 'undefined') return;
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch {
    // localStorage 용량 초과 등 에러 무시
  }
}

// --- Provider ---
export function FavoritesProvider({ children }: { children: ReactNode }) {
  const [favorites, setFavorites] = useState<FavoritesState>(defaultState);
  const [hydrated, setHydrated] = useState(false);

  // 클라이언트 hydration 시 localStorage에서 로드
  useEffect(() => {
    setFavorites(loadFromStorage());
    setHydrated(true);
  }, []);

  // 상태 변경 시 localStorage에 저장
  useEffect(() => {
    if (hydrated) {
      saveToStorage(favorites);
    }
  }, [favorites, hydrated]);

  const toggleFavorite = useCallback((type: FavoriteType, id: string) => {
    setFavorites((prev) => {
      const key = type === 'project' ? 'projects' : 'organizations';
      const list = prev[key];
      const isCurrentlyFav = list.includes(id);

      return {
        ...prev,
        [key]: isCurrentlyFav
          ? list.filter((item) => item !== id)
          : [...list, id],
      };
    });
  }, []);

  const isFavorite = useCallback(
    (type: FavoriteType, id: string): boolean => {
      const key = type === 'project' ? 'projects' : 'organizations';
      return favorites[key].includes(id);
    },
    [favorites]
  );

  const getFavoriteCount = useCallback((): number => {
    return favorites.projects.length + favorites.organizations.length;
  }, [favorites]);

  const getFavoritesByType = useCallback(
    (type: FavoriteType): string[] => {
      return type === 'project' ? favorites.projects : favorites.organizations;
    },
    [favorites]
  );

  const clearAll = useCallback(() => {
    setFavorites(defaultState);
  }, []);

  const value: FavoritesContextType = {
    favorites,
    toggleFavorite,
    isFavorite,
    getFavoriteCount,
    getFavoritesByType,
    clearAll,
  };

  return (
    <FavoritesContext.Provider value={value}>
      {children}
    </FavoritesContext.Provider>
  );
}

// --- 커스텀 훅 ---
export function useFavorites(): FavoritesContextType {
  const context = useContext(FavoritesContext);
  if (!context) {
    throw new Error('useFavorites must be used within a FavoritesProvider');
  }
  return context;
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { getDonations, minorToDisplay, type DonationsPage, type DonationItem } from '@/lib/api';
import { useAuth } from '@/contexts/AuthContext';

export interface UseDonationsResult {
  items: DonationItem[];
  total: number;
  page: number;
  pageSize: number;
  loading: boolean;
  error: string | null;
  setPage: (p: number) => void;
  refresh: () => void;
}

/**
 * 백엔드 /api/v1/me/donations 데이터를 가져오는 훅.
 * isRegistered가 true일 때만 호출합니다 (412 방지).
 */
export function useApiDonations(pageSize = 20): UseDonationsResult {
  const { isRegistered } = useAuth();
  const [page, setPage] = useState(1);
  const [data, setData] = useState<DonationsPage | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [tick, setTick] = useState(0);

  const refresh = useCallback(() => setTick((t) => t + 1), []);

  useEffect(() => {
    if (!isRegistered) return;

    let cancelled = false;
    setLoading(true);
    setError(null);

    getDonations(page, pageSize)
      .then((res) => {
        if (!cancelled) setData(res);
      })
      .catch((err: Error) => {
        if (!cancelled) setError(err.message ?? '기부 내역을 불러오지 못했습니다.');
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => { cancelled = true; };
  }, [isRegistered, page, pageSize, tick]);

  return {
    items: data?.items ?? [],
    total: data?.total ?? 0,
    page,
    pageSize,
    loading,
    error,
    setPage,
    refresh,
  };
}

// ── 편의 함수 ──────────────────────────────────────────────

/** donation_status → 배지 색상 */
export function statusColor(s: string): string {
  switch (s) {
    case 'succeeded': return 'green';
    case 'checkout_created': return 'yellow';
    case 'refunded': return 'red';
    default: return 'gray';
  }
}

/** donation_status → 표시 레이블 */
export function statusLabel(s: string): string {
  switch (s) {
    case 'succeeded': return 'Completed';
    case 'checkout_created': return 'Pending';
    case 'refunded': return 'Refunded';
    default: return s;
  }
}

/** minor 금액 → 통화 표시 문자열 */
export function formatMinor(minor: number, currency: string): string {
  const display = minorToDisplay(minor);
  return new Intl.NumberFormat('en-NZ', {
    style: 'currency',
    currency: currency || 'NZD',
    minimumFractionDigits: 0,
    maximumFractionDigits: 2,
  }).format(display);
}

